mapper.sql:
WHERE 1 = 1

    AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))


    AND u.status = #{status}

WHERE t.deleted = 0

    AND t.user_id = #{userId}


    AND t.type = #{type}


    AND t.occurred_at >= #{startAt}


    AND t.occurred_at < #{endAt}


    AND t.channel = #{channel}


    AND (
        u.username LIKE CONCAT('%', #{keyword}, '%')
        OR u.nickname LIKE CONCAT('%', #{keyword}, '%')
        OR t.item_name LIKE CONCAT('%', #{keyword}, '%')
        OR t.note LIKE CONCAT('%', #{keyword}, '%')
        OR t.online_app LIKE CONCAT('%', #{keyword}, '%')
        OR t.offline_place LIKE CONCAT('%', #{keyword}, '%')
        OR t.payment_method_name LIKE CONCAT('%', #{keyword}, '%')
        OR pm.name LIKE CONCAT('%', #{keyword}, '%')
        OR c.name LIKE CONCAT('%', #{keyword}, '%')
    )

mapper.select:
SELECT COUNT(*)
FROM transactions
WHERE deleted = 0
  AND occurred_at >= #{since}
  AND amount >= #{amountThreshold}

SELECT COUNT(*)
FROM (
    SELECT user_id, DATE(occurred_at) AS occurred_date, COUNT(*) AS transaction_count
    FROM transactions
    WHERE deleted = 0
      AND occurred_at >= #{since}
    GROUP BY user_id, DATE(occurred_at)
    HAVING COUNT(*) >= #{countThreshold}
) d

